  1	import React, { ComponentType, FC, useState } from 'react';
  2	import * as _ from 'lodash';
  3	
  4	import { K8sResourceKind } from '@openshift-console/dynamic-plugin-sdk';
  5	import { Alert, Bullseye, Button } from '@patternfly/react-core';
  6	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
  7	
  8	import Loading from '../Loading/Loading';
  9	
 10	import { EditorToggle, EditorType } from './EditorToggle';
 11	import { useEditorType } from './useEditorType';
 12	import { asyncYAMLToJS, safeJSToYAML } from './yaml';
 13	
 14	const YAML_KEY_ORDER = ['apiVerion', 'kind', 'metadata', 'spec', 'status'];
 15	export const YAML_TO_JS_OPTIONS = {
 16	  skipInvalid: true,
 17	  sortKeys: (a, b) => _.indexOf(YAML_KEY_ORDER, a) - _.indexOf(YAML_KEY_ORDER, b),
 18	};
 19	
 20	// Provides toggling and syncing between a form and yaml editor. The formData state is the source
 21	// of truth. Both the form editor and the yaml editor update the formData state. Here's the basic logic of this component:
 22	// In the form view:
 23	//   - formData is both rendered and updated by the form component
 24	//   - on toggle to YAML editor, yaml is parsed from current formData state.
 25	// In the YAML view:
 26	//   - on each yaml change, attempt to parse yaml to js:
 27	//       - If it fails, nothing happens. formData remains unchanged.
 28	//       - If successful, formData is updated to resulting js
 29	//   - on toggle to form view, no action needs to be taken to sync because formData has remained up to date with each yaml change
 30	//
 31	//  This means that when switching from YAML to Form, you can lose changes if the YAML editor contains unparsable YAML
 32	//  TODO Add an extra step when switching from yaml to form to warn user if they are about to lose changes.
 33	export const SyncedEditor: FC<SyncedEditorProps> = ({
 34	  context = {} as SyncedEditorProps['context'],
 35	  displayConversionError,
 36	  FormEditor,
 37	  initialData = {},
 38	  initialType = EditorType.Form,
 39	  lastViewUserSettingKey,
 40	  onChange = () => null,
 41	  onChangeEditorType = () => null,
 42	  prune,
 43	  YAMLEditor,
 44	}) => {
 45	  const { formContext, yamlContext } = context;
 46	  const { t } = useNetworkingTranslation();
 47	  const [formData, setFormData] = useState<K8sResourceKind>(initialData);
 48	  const [yaml, setYAML] = useState(
 49	    safeJSToYAML(initialData, 'yamlData', {
 50	      skipInvalid: true,
 51	    }),
 52	  );
 53	  const [switchError, setSwitchError] = useState<string | undefined>();
 54	  const [yamlWarning, setYAMLWarning] = useState<boolean>(false);
 55	  const [editorType, setEditorType, loaded] = useEditorType(lastViewUserSettingKey, initialType);
 56	
 57	  const handleFormDataChange = (newFormData: K8sResourceKind = {}) => {
 58	    if (!_.isEqual(newFormData, formData)) {
 59	      setFormData(newFormData);
 60	      onChange(newFormData);
 61	    }
 62	  };
 63	
 64	  const handleYAMLChange = (newYAML = '') => {
 65	    asyncYAMLToJS(newYAML)
 66	      .then((js) => {
 67	        setSwitchError(undefined);
 68	        handleFormDataChange(js);
 69	        setYAML(safeJSToYAML(prune?.(formData) ?? formData, yaml, YAML_TO_JS_OPTIONS));
 70	      })
 71	      .catch((err) => setSwitchError(String(err)));
 72	  };
 73	
 74	  const changeEditorType = (newType: EditorType): void => {
 75	    setEditorType(newType);
 76	    onChangeEditorType(newType);
 77	  };
 78	
 79	  const handleToggleToForm = () => {
 80	    if (switchError === undefined) {
 81	      changeEditorType(EditorType.Form);
 82	    } else {
 83	      setYAMLWarning(true);
 84	    }
 85	  };
 86	
 87	  const handleToggleToYAML = () => {
 88	    setYAML(safeJSToYAML(prune?.(formData) ?? formData, yaml, YAML_TO_JS_OPTIONS));
 89	    changeEditorType(EditorType.YAML);
 90	  };
 91	
 92	  const onClickYAMLWarningConfirm = () => {
 93	    setSwitchError(undefined);
 94	    setYAMLWarning(false);
 95	    changeEditorType(EditorType.Form);
 96	  };
 97	
 98	  const onClickYAMLWarningCancel = () => {
 99	    setYAMLWarning(false);
100	  };
101	
102	  const onChangeType = (newType) => {
103	    switch (newType) {
104	      case EditorType.YAML:
105	        handleToggleToYAML();
106	        break;
107	      case EditorType.Form:
108	        handleToggleToForm();
109	        break;
110	      default:
111	        break;
112	    }
113	  };
114	
115	  return loaded ? (
116	    <>
117	      <EditorToggle onChange={onChangeType} value={editorType} />
118	      {yamlWarning && (
119	        <Alert
120	          className="co-synced-editor__yaml-warning"
121	          isInline
122	          title={t('Invalid YAML cannot be persisted')}
123	          variant="danger"
124	        >
125	          {displayConversionError && <p>{switchError}</p>}
126	          <p>{t('Switching to form view will delete any invalid YAML.')}</p>
127	          <Button onClick={onClickYAMLWarningConfirm} variant="danger">
128	            {t('Switch and delete')}
129	          </Button>
130	          &nbsp;
131	          <Button onClick={onClickYAMLWarningCancel} variant="secondary">
132	            {t('Cancel')}
133	          </Button>
134	        </Alert>
135	      )}
136	      {editorType === EditorType.Form ? (
137	        <FormEditor
138	          formData={formData}
139	          onChange={handleFormDataChange}
140	          prune={prune}
141	          {...formContext}
142	        />
143	      ) : (
144	        <YAMLEditor initialYAML={yaml} onChange={handleYAMLChange} {...yamlContext} />
145	      )}
146	    </>
147	  ) : (
148	    <Bullseye>
149	      <Loading />
150	    </Bullseye>
151	  );
152	};
153	
154	type FormEditorProps = {
155	  formData?: K8sResourceKind;
156	  onChange?: (data: K8sResourceKind) => void;
157	  prune?: (data: K8sResourceKind) => any;
158	};
159	
160	type YAMLEditorProps = {
161	  initialYAML?: string;
162	  onChange?: (yaml: string) => void;
163	};
164	
165	type SyncedEditorProps = {
166	  context?: {
167	    formContext: { [key: string]: any };
168	    yamlContext: { [key: string]: any };
169	  };
170	  displayConversionError?: boolean;
171	  FormEditor: ComponentType<FormEditorProps>;
172	  initialData?: K8sResourceKind;
173	  initialType?: EditorType;
174	  lastViewUserSettingKey: string;
175	  onChange?: (data: K8sResourceKind) => void;
176	  onChangeEditorType?: (newType: EditorType) => void;
177	  prune?: (data: K8sResourceKind) => any;
178	  YAMLEditor: ComponentType<YAMLEditorProps>;
179	};

